    "R4": {"id": "run_1780250271", "config": "48p, lr=1e-6, len=1536, gen=8, temp=0.85, ep=2"},
}

for label, r in runs.items():
    rid = r["id"]
    # Read analysis.json
    try:
        with open(f"rllm_train/output/runs/{rid}/analysis.json") as f:
            a = json.load(f)
    except:
        a = {}

    # Read deep_analysis.json
    try:
        with open(f"rllm_train/output/runs/{rid}/deep_analysis.json") as f:
            d = json.load(f)
    except:
        d = {}

    # Read training log for final metrics
    log_path = f"rllm_train/output/runs/{rid}/training_log.txt"
    val_reward = clip_ratio = pg_loss = grad_norm = steps = "N/A"
    try:
        with open(log_path) as f:
            for line in f:
                if "val-aux/gsm8k/reward/mean@1:" in line:
                    val_reward = line.split(":")[-1].strip().rstrip(",")
                if "response_length/clip_ratio:" in line and "non_aborted" not in line:
                    clip_ratio = line.split(":")[-1].strip()
                if "actor/pg_loss:" in line:
                    pg_loss = line.split(":")[-1].strip()
                if "actor/grad_norm:" in line:
                    grad_norm = line.split(":")[-1].strip()
                if "Training Progress: 100%" in line:
                    # extract steps from 32/32 or 16/16 format
                    import re
                    m = re.search(r'(\d+)/(\d+)', line)
                    if m: steps = m.group(2)
    except:
        pass

    # Trajectory stats
    traj_dir = f"rllm_train/output/runs/{rid}/trajectories/"
    correct = total = truncated = 0
    try:
        for f in sorted(os.listdir(traj_dir)):
            if not f.endswith('.jsonl'): continue
            with open(os.path.join(traj_dir, f)) as fh:
                for line in fh:
                    if not line.strip(): continue
                    d = json.loads(line)
                    total += 1
                    if d.get('score', 0) >= 1.0: correct += 1
    except:
        pass

    train_reward = d.get("reward_avg", "N/A") if d else "N/A"
    alerts = [l["alerts"] for l in d.get("layers", []) if l.get("alerts")]

    print(f"--- {label}: {rid} ---")
    print(f"  Config:    {r['config']}")
    print(f"  Steps:     {steps}  |  Val: {val_reward}  |  Train: {train_reward}")
    print(f"  Traj:      {correct}/{total} correct ({100*correct/max(total,1):.1f}%)")
    print(f"  pg_loss:   {pg_loss}  |  grad_norm: {grad_norm}  |  clip_ratio: {clip_ratio}")
    print(f"  Alerts:    {alerts}")
    print()

